function parseMinutes(t) {
  if (!t) return 0;
  const [h,m] = t.split(":").map(Number);
  return (h||0)*60 + (m||0);
}
function fmtDuration(mins) {
  if (!mins || mins <= 0) return "0 שע׳ 00 דק׳";
  return `${Math.floor(mins/60)} שע׳ ${String(mins%60).padStart(2,"0")} דק׳`;
}
function tripMins(s) {
  const a = parseMinutes(s.startTime), b = parseMinutes(s.finishTime);
  return b > a ? b - a : 0;
}

